int main()
{
	int a,b,c,n;
	scanf("%d %d %d %d",&a,&b,&c,&n);
	int ans;
	ans=n-(a+b-c);
	if(ans<=0||c>a||c>b)
	printf("-1");
	else printf("%d",ans);


