use std::io;

fn main() {
    let mut s: String = String::new();
    io::stdin().read_line(&mut s).unwrap();
    let v: Vec<isize> = s.trim()
        .split(' ')
        .map(|n| n.parse().unwrap())
        .collect();

    let a = v[0];
    let b = v[1];
    let c = v[2];
    let n = v[3];

    let sol = n - a - b + c;

    if sol < 1 || c > a || c > b {
        println!("-1");
    } else {
        println!("{}", sol);
    }
}
